import{_ as n,j as e,o as t,v as h}from"./chunks/framework.OlxNbC8G.js";const i=JSON.parse('{"title":"World wide web là gì ?","description":"","frontmatter":{"footer":true,"title":"World wide web là gì ?","authors":["lethanh"],"date":"2024-03-18T00:00:00.000Z","outline":"deep","draft":true},"headers":[{"level":2,"title":"World wide web là gì ?","slug":"world-wide-web-la-gi","link":"#world-wide-web-la-gi","children":[]},{"level":2,"title":"Các thành phần của WWW (World Wide Web)","slug":"cac-thanh-phan-cua-www-world-wide-web","link":"#cac-thanh-phan-cua-www-world-wide-web","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md","filePath":"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md","lastUpdated":1710754627000}'),r={name:"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md"},a=[h('<p>Trong thế giới kỹ thuật số ngày nay, World Wide Web đã trở thành một phần không thể tách rời của Internet, là nơi diễn ra hàng loạt hoạt động từ học tập, làm việc đến giải trí.</p><p>Mặc dù vậy, không phải lập trình viên nào cũng thấu hiểu hoặc nắm rõ về World Wide Web và những tầng nền vững chắc mà nó dựa trên.</p><p>Hãy cùng nhau khám phá và mở rộng kiến thức về World Wide Web, một thế giới siêu văn bản rộng lớn nằm ngay dưới đầu ngón tay chúng ta.</p><nav class="table-of-contents"><ul><li><a href="#world-wide-web-la-gi">World wide web là gì ?</a></li><li><a href="#cac-thanh-phan-cua-www-world-wide-web">Các thành phần của WWW (World Wide Web)</a></li></ul></nav><h2 id="world-wide-web-la-gi" tabindex="-1">World wide web là gì ? <a class="header-anchor" href="#world-wide-web-la-gi" aria-label="Permalink to &quot;World wide web là gì ?&quot;">​</a></h2><ul><li><code>WWW</code> hay gọi chuẩn là <code>World Wide Web</code> là một hế thống thông tin toàn cầu dựa trên <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a>, cho phép người dùng truy cập vào các trang web và được liên kết với nhau thông qua siêu liên kết (hyperlinks).</li><li><code>WWW</code> là dịch vụ phổ biến nhất trên Internet, <code>WWW</code> bị nhiều người nhầm lẫn với <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a> nhưng thực chất đây là một trong những dịch vụ phổ biến của <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a> được cung cấp dưới dạng Web cho phép truy cập và chia sẻ thông tin thông qua web page dựa trên HTML và được liên kết với nhau thông qua Hyperlinks.</li><li>Như <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html#_4-su-bung-no-cua-world-wide-web-1990s">lịch sử đã được viết </a> WWW được phát minh bởi <a href="https://vi.wikipedia.org/wiki/Tim_Berners-Lee" target="_blank" rel="noreferrer">Tim Berners-Lee</a> vào năm 1989 và công bố vào năm 1990.</li><li><a href="https://vi.wikipedia.org/wiki/Tim_Berners-Lee" target="_blank" rel="noreferrer">Tim Berners-Lee</a> và các đồng nghiệp đã phát triển các công nghệ cơ bản như HTML, HTTP và URL để tạo lên nền tảng của WWW.</li><li>Ngày nay, <code>World Wide Web</code> là một phần không thể thiếu trong đời sống xã hội hiện đại, được sử dụng rộng rãi cho giáo dục, thông tin, giải trí, kinh doanh và nhiều lĩnh vực khác.</li></ul><h2 id="cac-thanh-phan-cua-www-world-wide-web" tabindex="-1">Các thành phần của WWW (World Wide Web) <a class="header-anchor" href="#cac-thanh-phan-cua-www-world-wide-web" aria-label="Permalink to &quot;Các thành phần của WWW (World Wide Web)&quot;">​</a></h2><p>WWW (World Wide Web) sẽ có 4 thành phần chính để có thể hoạt động.</p><ol><li>HyperText Markup Language (HTML): HTML là ngôn ngữ đánh dấu sử dụng các thẻ để tạo ra cấu trúc và nội dung cho các web page. Nó cho phép văn bảm, hình ảnh, video và nhiều dữ liệu khác được nhúng và hiển thị trên trình duyệt.</li><li>HyperText Transfer Protocol (HTTP): HTTP là giao thức truyền tải siêu văn bản, HTTP quy ước các thức dữ liệu được truyền tải trên web. Khi bạn nhập vào một URL trên trình duyệt, HTTP sẽ đưược kích hoatj</li></ol>',9)];const l=n(r,[["render",function(n,h,i,r,l,d){return t(),e("div",null,a)}]]);export{i as __pageData,l as default};
